  '{"id":"01KC7M021KMYX346XTS0YZT4MM","title":"PTO Exchange // New North Weekly Meeting","summary":null,"duration":33.810001373291016,"speakers":[],"sentences":[{"text":"How''s it going?","index":0,"end_time":192.39,"speaker_id":0,"start_time":191.83,"speaker_name":null},{"text":"Oh, good.","index":1,"end_time":194.31,"speaker_id":1,"start_time":193.51,"speaker_name":null},{"text":"I mean it''s been a full day of meetings and now I have to do the work.","index":2,"end_time":200.79,"speaker_id":1,"start_time":194.789,"speaker_name":null},{"text":"Totally get that.","index":3,"end_time":204.07,"speaker_id":0,"start_time":203.11,"speaker_name":null},{"text":"It.","index":4,"end_time":204.64,"speaker_id":2,"start_time":204.4,"speaker_name":null},{"text":"Doing.","index":5,"end_time":247.29,"speaker_id":3,"start_time":247.05,"speaker_name":null},{"text":"Hey, Sam, how''s it going?","index":6,"end_time":251.29,"speaker_id":3,"start_time":248.89,"speaker_name":null},{"text":"Hi.","index":7,"end_time":252.09,"speaker_id":1,"start_time":251.61,"speaker_name":null},{"text":"Hi, Nina.","index":8,"end_time":253.69,"speaker_id":3,"start_time":252.89,"speaker_name":null},{"text":"How you guys doing?","index":9,"end_time":254.89,"speaker_id":3,"start_time":253.85,"speaker_name":null},{"text":"Packing it all in, man, before next week.","index":10,"end_time":258.66,"speaker_id":0,"start_time":256.66,"speaker_name":null},{"text":"Getting ready for the holidays.","index":11,"end_time":261.14,"speaker_id":3,"start_time":259.54,"speaker_name":null},{"text":"Yeah.","index":12,"end_time":261.94,"speaker_id":0,"start_time":261.46,"speaker_name":null},{"text":"Any big travel?","index":13,"end_time":263.7,"speaker_id":3,"start_time":262.66,"speaker_name":null},{"text":"Colin or.","index":14,"end_time":264.38,"speaker_id":3,"start_time":263.7,"speaker_name":null},{"text":"No, thankfully, no.","index":15,"end_time":266.82,"speaker_id":0,"start_time":264.38,"speaker_name":null},{"text":"That''s good.","index":16,"end_time":268.42,"speaker_id":3,"start_time":267.7,"speaker_name":null},{"text":"Yeah.","index":17,"end_time":268.94,"speaker_id":0,"start_time":268.5,"speaker_name":null},{"text":"Nina, do you have any travel?","index":18,"end_time":270.5,"speaker_id":3,"start_time":268.94,"speaker_name":null},{"text":"No, not really.","index":19,"end_time":272.18,"speaker_id":1,"start_time":271.219,"speaker_name":null},{"text":"Just.","index":20,"end_time":272.66,"speaker_id":1,"start_time":272.26,"speaker_name":null},{"text":"That''s always.","index":21,"end_time":274.58,"speaker_id":3,"start_time":273.94,"speaker_name":null},{"text":"How about you?","index":22,"end_time":277.46,"speaker_id":0,"start_time":276.74,"speaker_name":null},{"text":"No, just local.","index":23,"end_time":280.5,"speaker_id":3,"start_time":278.74,"speaker_name":null},{"text":"We''re.","index":24,"end_time":281.14,"speaker_id":3,"start_time":280.66,"speaker_name":null},{"text":"I got like a lot of places to be but it''s all local, like driving distance and stuff.","index":25,"end_time":287.19,"speaker_id":3,"start_time":281.3,"speaker_name":null},{"text":"So.","index":26,"end_time":287.59,"speaker_id":3,"start_time":287.19,"speaker_name":null},{"text":"Yeah, my longest drive''s like an hour.","index":27,"end_time":289.19,"speaker_id":0,"start_time":287.59,"speaker_name":null},{"text":"Yeah, it''s not too bad, but it.","index":28,"end_time":292.15,"speaker_id":3,"start_time":289.99,"speaker_name":null},{"text":"Should be good north of Baltimore.","index":29,"end_time":295.11,"speaker_id":0,"start_time":292.15,"speaker_name":null},{"text":"I don''t know if you know, like.","index":30,"end_time":296.07,"speaker_id":0,"start_time":295.11,"speaker_name":null},{"text":"Do you know Maryland well?","index":31,"end_time":297.83,"speaker_id":0,"start_time":296.31,"speaker_name":null},{"text":"A little bit, yeah.","index":32,"end_time":299.35,"speaker_id":3,"start_time":297.91,"speaker_name":null},{"text":"It''s.","index":33,"end_time":300.15,"speaker_id":0,"start_time":299.67,"speaker_name":null},{"text":"It''s a place called Moncton.","index":34,"end_time":301.389,"speaker_id":0,"start_time":300.15,"speaker_name":null},{"text":"It''s like north of Bel Air in Baltimore.","index":35,"end_time":303.43,"speaker_id":0,"start_time":301.389,"speaker_name":null},{"text":"I know Bel Air.","index":36,"end_time":304.47,"speaker_id":3,"start_time":303.51,"speaker_name":null},{"text":"Yeah, I don''t know Moncton, but yeah.","index":37,"end_time":308.23,"speaker_id":3,"start_time":304.87,"speaker_name":null},{"text":"Big week.","index":38,"end_time":309.35,"speaker_id":3,"start_time":308.55,"speaker_name":null},{"text":"It''s my birthday this week, Joe, so I got a lot.","index":39,"end_time":312.23,"speaker_id":3,"start_time":309.51,"speaker_name":null},{"text":"What day?","index":40,"end_time":312.79,"speaker_id":0,"start_time":312.31,"speaker_name":null},{"text":"December 24th.","index":41,"end_time":315.9,"speaker_id":3,"start_time":314.86,"speaker_name":null},{"text":"It''s my brother in law''s birthday too.","index":42,"end_time":319.02,"speaker_id":0,"start_time":317.18,"speaker_name":null},{"text":"Yep.","index":43,"end_time":320.18,"speaker_id":3,"start_time":319.74,"speaker_name":null},{"text":"There you go.","index":44,"end_time":320.74,"speaker_id":3,"start_time":320.18,"speaker_name":null},{"text":"Big, big time of year.","index":45,"end_time":322.54,"speaker_id":3,"start_time":320.74,"speaker_name":null},{"text":"December.","index":46,"end_time":323.34,"speaker_id":3,"start_time":322.7,"speaker_name":null},{"text":"Always got to do a birthday and a Christmas gift.","index":47,"end_time":326.06,"speaker_id":0,"start_time":323.42,"speaker_name":null},{"text":"Yeah, got it all.","index":48,"end_time":327.3,"speaker_id":3,"start_time":326.22,"speaker_name":null},{"text":"Competing with Jesus is my Stacy.","index":49,"end_time":329.5,"speaker_id":1,"start_time":327.3,"speaker_name":null},{"text":"I. I mean I. I got it all.","index":50,"end_time":333.1,"speaker_id":3,"start_time":330.78,"speaker_name":null},{"text":"My.","index":51,"end_time":333.42,"speaker_id":3,"start_time":333.1,"speaker_name":null},{"text":"So my girlfriend is Christian, so they obviously all do like Christmas stuff.","index":52,"end_time":338.94,"speaker_id":3,"start_time":333.5,"speaker_name":null},{"text":"I''m Jewish, so.","index":53,"end_time":340.51,"speaker_id":3,"start_time":339.02,"speaker_name":null},{"text":"So we do Hanukkah and stuff and we got like birthday stuff that we''re doing as well.","index":54,"end_time":346.82,"speaker_id":3,"start_time":340.66,"speaker_name":null},{"text":"So I mean, yeah, we.","index":55,"end_time":348.58,"speaker_id":3,"start_time":346.9,"speaker_name":null},{"text":"I got like a lot of different places that we have to go, but it should be fun.","index":56,"end_time":353.78,"speaker_id":3,"start_time":348.66,"speaker_name":null},{"text":"Nice.","index":57,"end_time":354.82,"speaker_id":0,"start_time":354.34,"speaker_name":null},{"text":"Hey, Josh.","index":58,"end_time":355.78,"speaker_id":0,"start_time":355.06,"speaker_name":null},{"text":"Hey, what''s up, Colin?","index":59,"end_time":357.3,"speaker_id":2,"start_time":356.18,"speaker_name":null},{"text":"How you guys doing?","index":60,"end_time":358.1,"speaker_id":0,"start_time":357.38,"speaker_name":null},{"text":"How you doing?","index":61,"end_time":358.74,"speaker_id":2,"start_time":358.1,"speaker_name":null},{"text":"Good.","index":62,"end_time":359.46,"speaker_id":2,"start_time":359.06,"speaker_name":null},{"text":"Awesome.","index":63,"end_time":361.62,"speaker_id":0,"start_time":361.14,"speaker_name":null},{"text":"All right, well let''s jump into it and then I also want to have some time at the end to talk about, I don''t know your guys holiday schedule or your office hours next week.","index":64,"end_time":369.18,"speaker_id":0,"start_time":361.62,"speaker_name":null},{"text":"So I want to make sure that we''re locked in there.","index":65,"end_time":371.38,"speaker_id":0,"start_time":369.18,"speaker_name":null},{"text":"There.","index":66,"end_time":371.97,"speaker_id":3,"start_time":371.73,"speaker_name":null},{"text":"Sure.","index":67,"end_time":373.09,"speaker_id":3,"start_time":372.69,"speaker_name":null},{"text":"Right.","index":68,"end_time":374.69,"speaker_id":0,"start_time":374.29,"speaker_name":null},{"text":"So diving in.","index":69,"end_time":379.09,"speaker_id":0,"start_time":377.49,"speaker_name":null},{"text":"So we have written copy for the employee Persona page, the HR Persona page and the industry pages as well.","index":70,"end_time":392.21,"speaker_id":0,"start_time":383.65,"speaker_name":null},{"text":"So we''ll send over those documents.","index":71,"end_time":394.37,"speaker_id":0,"start_time":392.37,"speaker_name":null},{"text":"We are going to go ahead and get started with design just based on how the last batch went.","index":72,"end_time":398.57,"speaker_id":0,"start_time":394.93,"speaker_name":null},{"text":"It didn''t seem like we had.","index":73,"end_time":399.65,"speaker_id":0,"start_time":398.57,"speaker_name":null},{"text":"It was mainly just like subtle text changes, things like that.","index":74,"end_time":402.29,"speaker_id":0,"start_time":399.65,"speaker_name":null},{"text":"So we have all of those documents ready for you guys to review.","index":75,"end_time":407.03,"speaker_id":0,"start_time":404.71,"speaker_name":null},{"text":"One thing I''ll call out is on the pursuit or on the industry pages we have like, we start with the base industry pages that will also List all the industries, and then there''s going to be a drop down that we''re planning that''ll go into all of the specific industries themselves.","index":76,"end_time":424.71,"speaker_id":0,"start_time":408.71,"speaker_name":null},{"text":"So we have all of that copy in one document.","index":77,"end_time":428.83,"speaker_id":0,"start_time":426.71,"speaker_name":null},{"text":"Cool.","index":78,"end_time":430.02,"speaker_id":3,"start_time":429.7,"speaker_name":null},{"text":"You can send those over.","index":79,"end_time":431.14,"speaker_id":3,"start_time":430.02,"speaker_name":null},{"text":"I''ll take a look and make any notes or edits on them.","index":80,"end_time":434.98,"speaker_id":3,"start_time":431.22,"speaker_name":null},{"text":"Perfect.","index":81,"end_time":435.78,"speaker_id":0,"start_time":435.3,"speaker_name":null},{"text":"All right.","index":82,"end_time":438.26,"speaker_id":0,"start_time":437.7,"speaker_name":null},{"text":"And then we also are working on the slide deck.","index":83,"end_time":442.5,"speaker_id":0,"start_time":438.74,"speaker_name":null},{"text":"And so we have kind of some mock ups that Nina was working on that she gave to the designers.","index":84,"end_time":450.82,"speaker_id":0,"start_time":444.34,"speaker_name":null},{"text":"Obviously going to use your brand colors, but thinking of different clean ways that we can present the data, some icons.","index":85,"end_time":458.18,"speaker_id":0,"start_time":452.26,"speaker_name":null},{"text":"Of course, I''m getting hit with a refresh right now, but we have some of the different ways to display some data baked into these and then cool boxes and things that we can do.","index":86,"end_time":470.19,"speaker_id":0,"start_time":459.07,"speaker_name":null},{"text":"So we are working on that.","index":87,"end_time":478.83,"speaker_id":0,"start_time":477.55,"speaker_name":null},{"text":"Nina, what''s the delivery date on that?","index":88,"end_time":481.59,"speaker_id":0,"start_time":479.47,"speaker_name":null},{"text":"Can you remind me.","index":89,"end_time":482.43,"speaker_id":0,"start_time":481.59,"speaker_name":null},{"text":"Second.","index":90,"end_time":484.81,"speaker_id":1,"start_time":484.57,"speaker_name":null},{"text":"For the presentation deck?","index":91,"end_time":497.45,"speaker_id":1,"start_time":495.61,"speaker_name":null},{"text":"It''s Monday next week.","index":92,"end_time":500.33,"speaker_id":1,"start_time":497.93,"speaker_name":null},{"text":"Okay, perfect.","index":93,"end_time":502.97,"speaker_id":0,"start_time":500.489,"speaker_name":null},{"text":"And then we also, as we talked about, created some new ads that got launched for the Benchmark Report.","index":94,"end_time":508.25,"speaker_id":0,"start_time":503.21,"speaker_name":null},{"text":"So we wanted to show just more of a preview of what the actual Benchmark Report contains.","index":95,"end_time":512.73,"speaker_id":0,"start_time":508.41,"speaker_name":null},{"text":"And again, kind of just diving into the competitive edge that most HR professionals are feeling.","index":96,"end_time":520.84,"speaker_id":0,"start_time":514.28,"speaker_name":null},{"text":"Gotcha.","index":97,"end_time":522.28,"speaker_id":3,"start_time":521.56,"speaker_name":null},{"text":"Okay.","index":98,"end_time":523.24,"speaker_id":3,"start_time":522.6,"speaker_name":null},{"text":"Those look good.","index":99,"end_time":524.12,"speaker_id":3,"start_time":523.32,"speaker_name":null},{"text":"I like them.","index":100,"end_time":524.84,"speaker_id":3,"start_time":524.12,"speaker_name":null},{"text":"Awesome.","index":101,"end_time":526.24,"speaker_id":0,"start_time":525.64,"speaker_name":null},{"text":"Yeah.","index":102,"end_time":526.68,"speaker_id":0,"start_time":526.24,"speaker_name":null},{"text":"So we got these variations running against each other, and we''ll see how they perform.","index":103,"end_time":530.04,"speaker_id":0,"start_time":526.68,"speaker_name":null},{"text":"Sounds great.","index":104,"end_time":533.64,"speaker_id":2,"start_time":532.92,"speaker_name":null},{"text":"Awesome.","index":105,"end_time":534.84,"speaker_id":0,"start_time":534.2,"speaker_name":null},{"text":"Yeah.","index":106,"end_time":536.56,"speaker_id":0,"start_time":536.12,"speaker_name":null},{"text":"So sending over those.","index":107,"end_time":538.28,"speaker_id":0,"start_time":536.56,"speaker_name":null},{"text":"And then also, Josh, we hit a snack with our video team, so that demo video will be delivered on Tuesday.","index":108,"end_time":544.35,"speaker_id":0,"start_time":538.36,"speaker_name":null},{"text":"Does that still work for your timeline?","index":109,"end_time":547.71,"speaker_id":0,"start_time":546.19,"speaker_name":null},{"text":"Yeah, I mean, the sooner the better.","index":110,"end_time":549.55,"speaker_id":2,"start_time":548.27,"speaker_name":null},{"text":"We.","index":111,"end_time":549.87,"speaker_id":2,"start_time":549.55,"speaker_name":null},{"text":"We had told the client we''d get it back to him at the end of this week, but if we can just let them know it''s a day or two behind.","index":112,"end_time":554.67,"speaker_id":2,"start_time":549.87,"speaker_name":null},{"text":"They''re not going live until January 1st, but they want to be able to review it as soon as they can.","index":113,"end_time":559.23,"speaker_id":2,"start_time":554.75,"speaker_name":null},{"text":"So.","index":114,"end_time":559.55,"speaker_id":0,"start_time":559.23,"speaker_name":null},{"text":"Yeah, gotcha.","index":115,"end_time":560.59,"speaker_id":0,"start_time":559.63,"speaker_name":null},{"text":"Yeah, we''ll have that to you on Tuesday then.","index":116,"end_time":563.43,"speaker_id":0,"start_time":560.59,"speaker_name":null},{"text":"We''ve also created or are working on an end of the year compilation video from all of the podcast episodes that have been recorded as well.","index":117,"end_time":570.27,"speaker_id":0,"start_time":563.43,"speaker_name":null},{"text":"I don''t think that it would be best to put those on, like Spotify or anything.","index":118,"end_time":574.83,"speaker_id":0,"start_time":572.07,"speaker_name":null},{"text":"I think, Sam, those are purely a social media play.","index":119,"end_time":578.15,"speaker_id":0,"start_time":574.83,"speaker_name":null},{"text":"Okay, we can do that with all.","index":120,"end_time":581.67,"speaker_id":3,"start_time":578.79,"speaker_name":null},{"text":"Yeah.","index":121,"end_time":582.15,"speaker_id":3,"start_time":581.67,"speaker_name":null},{"text":"All right, so we''ll send over all of these for review and then just taking a look at some metrics.","index":122,"end_time":589.35,"speaker_id":0,"start_time":584.39,"speaker_name":null},{"text":"So we got 367 clicks on the Benchmark Report campaign, and obviously we''re not seeing 367 people fill the Benchmark Report out.","index":123,"end_time":599.75,"speaker_id":0,"start_time":589.83,"speaker_name":null},{"text":"So we''re looking at making changes on the landing page and then also creating a.","index":124,"end_time":605.49,"speaker_id":0,"start_time":599.83,"speaker_name":null},{"text":"Some sort of document.","index":125,"end_time":607.57,"speaker_id":0,"start_time":606.37,"speaker_name":null},{"text":"And I wanted to talk to you guys about this.","index":126,"end_time":609.33,"speaker_id":0,"start_time":607.57,"speaker_name":null},{"text":"So on LinkedIn lead gen forms, you can run where they download a document directly from it and we see high conversion rates there as well.","index":127,"end_time":616.93,"speaker_id":0,"start_time":609.81,"speaker_name":null},{"text":"I know that you guys have done some white papers and things like that in the past.","index":128,"end_time":620.53,"speaker_id":0,"start_time":617.25,"speaker_name":null},{"text":"I like to go even a little bit lighter on them sometimes where it''s like a checklist.","index":129,"end_time":625.57,"speaker_id":0,"start_time":621.49,"speaker_name":null},{"text":"And I think that could be really relevant to some HR professionals who.","index":130,"end_time":629.57,"speaker_id":0,"start_time":626.21,"speaker_name":null},{"text":"Where they''re just evaluating themselves at the end of the year or beginning of the year and the policies that they have in place or their retention rates.","index":131,"end_time":636.52,"speaker_id":0,"start_time":629.64,"speaker_name":null},{"text":"And it''s kind of like a checklist to make sure that they''re performing to the best of their abilities and then obviously plugging a tool like PTO Exchange in and how that can enhance.","index":132,"end_time":643.88,"speaker_id":0,"start_time":636.52,"speaker_name":null},{"text":"Is that something new that we would create, you''re suggesting?","index":133,"end_time":649.32,"speaker_id":3,"start_time":645.4,"speaker_name":null},{"text":"Yeah.","index":134,"end_time":649.96,"speaker_id":0,"start_time":649.48,"speaker_name":null},{"text":"As like a white paper download for some of our LinkedIn ad campaigns.","index":135,"end_time":658.28,"speaker_id":3,"start_time":653.64,"speaker_name":null},{"text":"Yeah, so like a lead gen form that has a download link for the PDF instead of them going to the webpage.","index":136,"end_time":664.51,"speaker_id":1,"start_time":658.59,"speaker_name":null},{"text":"Okay, yeah.","index":137,"end_time":666.83,"speaker_id":3,"start_time":665.79,"speaker_name":null},{"text":"I mean, I think that''s something we can, we can work on.","index":138,"end_time":670.27,"speaker_id":3,"start_time":666.83,"speaker_name":null},{"text":"Awesome.","index":139,"end_time":671.63,"speaker_id":0,"start_time":670.99,"speaker_name":null},{"text":"Yeah.","index":140,"end_time":671.99,"speaker_id":0,"start_time":671.63,"speaker_name":null},{"text":"Because basically we want to test, obviously we''re making a lot of enhancements to the website and so we''re still going to have ads that are sending traffic there, but also want to see if, if we lessen the barrier where they don''t even have to go to the website, they can just fill out their information on LinkedIn, how that can improve conversion rates.","index":141,"end_time":688.4,"speaker_id":0,"start_time":671.99,"speaker_name":null},{"text":"Okay, let''s.","index":142,"end_time":692.4,"speaker_id":3,"start_time":689.84,"speaker_name":null},{"text":"Yeah, let''s, I guess, think about what we want to put together for that.","index":143,"end_time":697.2,"speaker_id":3,"start_time":692.4,"speaker_name":null},{"text":"Yeah, yeah.","index":144,"end_time":698.56,"speaker_id":0,"start_time":697.6,"speaker_name":null},{"text":"I mean, I was thinking the HR checklist could even do one for more of the financial roles as well.","index":145,"end_time":705.36,"speaker_id":0,"start_time":698.56,"speaker_name":null},{"text":"Have you guys done a checklist before?","index":146,"end_time":709.28,"speaker_id":0,"start_time":707.68,"speaker_name":null},{"text":"We have a like financial wellness checklist for employers that''s like all about like financial wellness for employees and like what you need to offer to make sure your employees are financially healthy that we could probably repurpose and reuse.","index":147,"end_time":729.69,"speaker_id":3,"start_time":710.97,"speaker_name":null},{"text":"It''s a couple years old, so it probably needs an update anyway, but.","index":148,"end_time":735.69,"speaker_id":3,"start_time":729.77,"speaker_name":null},{"text":"So maybe we use something like that.","index":149,"end_time":739.3,"speaker_id":3,"start_time":737.86,"speaker_name":null},{"text":"Yeah, I think we use that as a starting point.","index":150,"end_time":741.3,"speaker_id":0,"start_time":739.46,"speaker_name":null},{"text":"Update that and then make a version for hr.","index":151,"end_time":743.7,"speaker_id":0,"start_time":741.46,"speaker_name":null},{"text":"Okay, awesome.","index":152,"end_time":746.82,"speaker_id":3,"start_time":744.34,"speaker_name":null},{"text":"We''re getting very good depth and frequency as far as the audience that we''re advertising to.","index":153,"end_time":752.139,"speaker_id":0,"start_time":747.54,"speaker_name":null},{"text":"So we''ve compared to competitors.","index":154,"end_time":754.98,"speaker_id":0,"start_time":752.139,"speaker_name":null},{"text":"We''ve reached 37% into the targeted HR list and they''re seeing ads upwards of seven or eight times and they''ve been engaging and clicking.","index":155,"end_time":762.94,"speaker_id":0,"start_time":755.22,"speaker_name":null},{"text":"It''s just we''re losing them on filling out the form form for the benchmark report itself.","index":156,"end_time":766.52,"speaker_id":0,"start_time":762.94,"speaker_name":null},{"text":"So that''s why we''re looking at different changes we can make on the landing page.","index":157,"end_time":770.68,"speaker_id":0,"start_time":767.88,"speaker_name":null},{"text":"And a lot of HR directors and VPs.","index":158,"end_time":775.64,"speaker_id":0,"start_time":773.64,"speaker_name":null},{"text":"So Giant Food, Friedman, Vartolo and this very large recycling company as well.","index":159,"end_time":782.44,"speaker_id":0,"start_time":776.04,"speaker_name":null},{"text":"On the adroll side, again strictly an awareness play.","index":160,"end_time":787.04,"speaker_id":0,"start_time":784.28,"speaker_name":null},{"text":"So not seeing direct conversions come from it.","index":161,"end_time":789,"speaker_id":0,"start_time":787.04,"speaker_name":null},{"text":"But it is retargeting through a pixel and bringing people back to your site on a regular basis and that''s running against the negative list of your customers as well.","index":162,"end_time":796.24,"speaker_id":0,"start_time":789,"speaker_name":null},{"text":"So we''re not wasting money on them.","index":163,"end_time":797.62,"speaker_id":0,"start_time":796.24,"speaker_name":null},{"text":"Okay, cool.","index":164,"end_time":799.78,"speaker_id":3,"start_time":798.5,"speaker_name":null},{"text":"And that is everything that we had to go through.","index":165,"end_time":804.9,"speaker_id":0,"start_time":802.1,"speaker_name":null},{"text":"So one thing I do want to make time before I ask if you guys have any questions.","index":166,"end_time":809.62,"speaker_id":0,"start_time":804.98,"speaker_name":null},{"text":"Our next meeting is slated for Christmas.","index":167,"end_time":812.539,"speaker_id":0,"start_time":810.74,"speaker_name":null},{"text":"We are closed on that day.","index":168,"end_time":814.74,"speaker_id":0,"start_time":812.539,"speaker_name":null},{"text":"We have our other meeting on Monday as well.","index":169,"end_time":817.14,"speaker_id":0,"start_time":814.9,"speaker_name":null},{"text":"So what does your guys holiday schedule look like next week?","index":170,"end_time":821.22,"speaker_id":0,"start_time":818.02,"speaker_name":null},{"text":"I mean we are off on Christmas as you would expect.","index":171,"end_time":825.63,"speaker_id":2,"start_time":823.07,"speaker_name":null},{"text":"I mean technically we don''t have either the 24th and the 26th off, but you know, those are pretty light days usually.","index":172,"end_time":834.51,"speaker_id":2,"start_time":827.55,"speaker_name":null},{"text":"So we try to not schedule meetings those days, you know, if we can avoid it.","index":173,"end_time":841.23,"speaker_id":2,"start_time":834.51,"speaker_name":null},{"text":"So if we''re just meeting once next week, that should be fine.","index":174,"end_time":846.27,"speaker_id":2,"start_time":842.83,"speaker_name":null},{"text":"Cool.","index":175,"end_time":846.95,"speaker_id":0,"start_time":846.51,"speaker_name":null},{"text":"So we''ll keep our Monday and then I''ll have assets on Monday and assets on Tuesday to send over.","index":176,"end_time":852.06,"speaker_id":0,"start_time":846.95,"speaker_name":null},{"text":"I''ll cancel our Christmas Day meeting.","index":177,"end_time":854.14,"speaker_id":0,"start_time":852.06,"speaker_name":null},{"text":"Unless you guys want to just hop on and talk, you know, just let me know.","index":178,"end_time":858.22,"speaker_id":0,"start_time":854.14,"speaker_name":null},{"text":"I''m okay, but thank you.","index":179,"end_time":861.74,"speaker_id":3,"start_time":860.3,"speaker_name":null},{"text":"And then what, what''s the.","index":180,"end_time":865.42,"speaker_id":2,"start_time":864.14,"speaker_name":null},{"text":"What''s getting delivered on Monday?","index":181,"end_time":866.94,"speaker_id":2,"start_time":865.5,"speaker_name":null},{"text":"That will be the slide deck.","index":182,"end_time":870.3,"speaker_id":0,"start_time":867.74,"speaker_name":null},{"text":"Okay, sorry, I think I missed that at the beginning of the call.","index":183,"end_time":872.54,"speaker_id":2,"start_time":870.38,"speaker_name":null},{"text":"Yep, Slide deck Monday and then the demo video Tuesday.","index":184,"end_time":877.43,"speaker_id":0,"start_time":874.23,"speaker_name":null},{"text":"And those ads are already live as well.","index":185,"end_time":881.03,"speaker_id":0,"start_time":879.27,"speaker_name":null},{"text":"Awesome.","index":186,"end_time":882.31,"speaker_id":3,"start_time":881.75,"speaker_name":null},{"text":"The other thing that I, I wanted to let you guys know.","index":187,"end_time":886.79,"speaker_id":3,"start_time":883.27,"speaker_name":null},{"text":"So I am.","index":188,"end_time":889.59,"speaker_id":3,"start_time":888.15,"speaker_name":null},{"text":"I''ve actually accepted another position.","index":189,"end_time":892.87,"speaker_id":3,"start_time":890.55,"speaker_name":null},{"text":"So I''m going to be leaving PTO exchange in the next, you know, week or so.","index":190,"end_time":899.11,"speaker_id":3,"start_time":893.51,"speaker_name":null},{"text":"But we''re still working out the details.","index":191,"end_time":904.12,"speaker_id":3,"start_time":901.04,"speaker_name":null},{"text":"You know, I''m talking with Rob and Josh.","index":192,"end_time":906.08,"speaker_id":3,"start_time":904.12,"speaker_name":null},{"text":"I will be available for them in the interim time as they look for a replacement as they transition the role.","index":193,"end_time":915.52,"speaker_id":3,"start_time":906.88,"speaker_name":null},{"text":"I''m going to be available to give them hours like on the weekends and at nights and stuff to help handle some of the marketing activities that we''re doing.","index":194,"end_time":926.65,"speaker_id":3,"start_time":915.76,"speaker_name":null},{"text":"So I anticipate that I won''t go away completely, Colin.","index":195,"end_time":931.61,"speaker_id":3,"start_time":926.73,"speaker_name":null},{"text":"Like I''ll.","index":196,"end_time":932.01,"speaker_id":3,"start_time":931.61,"speaker_name":null},{"text":"I''ll probably still be communicating with you guys and helping get some of these deliverables to you and help.","index":197,"end_time":937.89,"speaker_id":3,"start_time":932.01,"speaker_name":null},{"text":"Help review copy and things like that.","index":198,"end_time":940.25,"speaker_id":3,"start_time":937.89,"speaker_name":null},{"text":"I just won''t be available for, like, our weekly huddles, basically, so we''ll have more details on, like, how that relationship will work, but I want to let you guys know.","index":199,"end_time":952.73,"speaker_id":3,"start_time":941.85,"speaker_name":null},{"text":"Yeah, I appreciate that.","index":200,"end_time":954.21,"speaker_id":0,"start_time":953.25,"speaker_name":null},{"text":"A bittersweet congratulations.","index":201,"end_time":959.01,"speaker_id":0,"start_time":956.69,"speaker_name":null},{"text":"Yeah.","index":202,"end_time":961.49,"speaker_id":0,"start_time":961.01,"speaker_name":null},{"text":"Glad that we can still have some communication, but yeah, happy for you.","index":203,"end_time":966.13,"speaker_id":0,"start_time":961.81,"speaker_name":null},{"text":"Bumped that we won''t be on our regular sinks, but.","index":204,"end_time":970.53,"speaker_id":0,"start_time":967.33,"speaker_name":null},{"text":"Yeah, I mean, that''s how it goes.","index":205,"end_time":972.61,"speaker_id":0,"start_time":970.69,"speaker_name":null},{"text":"Yeah.","index":206,"end_time":973.81,"speaker_id":3,"start_time":973.33,"speaker_name":null},{"text":"And you''ve been great throughout this relationship that we''ve had.","index":207,"end_time":979.01,"speaker_id":3,"start_time":974.77,"speaker_name":null},{"text":"Really appreciate all the hard work that you and New north and Nina all do for us.","index":208,"end_time":983.62,"speaker_id":3,"start_time":979.17,"speaker_name":null},{"text":"So that''s been much appreciated.","index":209,"end_time":985.42,"speaker_id":3,"start_time":983.62,"speaker_name":null},{"text":"You''ve certainly made my time at PTO Exchange, you know, a little bit better and easier.","index":210,"end_time":992.34,"speaker_id":3,"start_time":985.42,"speaker_name":null},{"text":"We''ve been able to do a lot more things with you guys on our side, so that was good.","index":211,"end_time":996.66,"speaker_id":3,"start_time":992.34,"speaker_name":null},{"text":"Yeah, I appreciate that.","index":212,"end_time":997.74,"speaker_id":0,"start_time":996.9,"speaker_name":null},{"text":"It''s been great working with you as well.","index":213,"end_time":999.06,"speaker_id":0,"start_time":997.74,"speaker_name":null},{"text":"Yeah, go ahead, Josh.","index":214,"end_time":1001.54,"speaker_id":0,"start_time":1000.5,"speaker_name":null},{"text":"With that said, one of the things I would like to better understand, and I think Sam, this would take the three of us getting on a call and talking about, but like, some of the more administrative stuff, operational stuff specific to HubSpot that Sam currently does, is that work that New north can take on.","index":215,"end_time":1032.15,"speaker_id":2,"start_time":1003.3,"speaker_name":null},{"text":"Yeah, absolutely.","index":216,"end_time":1033.75,"speaker_id":0,"start_time":1032.63,"speaker_name":null},{"text":"Um, and Sam, I don''t know how easy it is for you to kind of like outline all the stuff that you do in HubSpot.","index":217,"end_time":1044,"speaker_id":2,"start_time":1035.36,"speaker_name":null},{"text":"Cause I know it''s a ton, but, like, is that something that you could put together?","index":218,"end_time":1049.6,"speaker_id":2,"start_time":1044,"speaker_name":null},{"text":"And we have that as a. I don''t know if that''s like our entire meeting on Monday or if.","index":219,"end_time":1054.24,"speaker_id":2,"start_time":1049.6,"speaker_name":null},{"text":"If we need.","index":220,"end_time":1055.16,"speaker_id":2,"start_time":1054.56,"speaker_name":null},{"text":"We need to schedule like a secondary meeting, but to.","index":221,"end_time":1058.64,"speaker_id":2,"start_time":1055.16,"speaker_name":null},{"text":"For us to get a better idea.","index":222,"end_time":1060.08,"speaker_id":2,"start_time":1058.64,"speaker_name":null},{"text":"And I want Rob involved in that conversation also.","index":223,"end_time":1062.38,"speaker_id":2,"start_time":1060.08,"speaker_name":null},{"text":"Either full time that we.","index":224,"end_time":1067.78,"speaker_id":2,"start_time":1065.42,"speaker_name":null},{"text":"That we have.","index":225,"end_time":1068.34,"speaker_id":2,"start_time":1067.78,"speaker_name":null},{"text":"You guys take this.","index":226,"end_time":1069.58,"speaker_id":2,"start_time":1068.34,"speaker_name":null},{"text":"This part of Sam''s job on or as a stopgap while we ramp up the next person.","index":227,"end_time":1077.58,"speaker_id":2,"start_time":1069.74,"speaker_name":null},{"text":"But it would be a couple months or whatever it''s going to be until that person''s like, fully comfortable with the way that our processes work and then they kind of take it back from you.","index":228,"end_time":1087.7,"speaker_id":2,"start_time":1077.58,"speaker_name":null},{"text":"Right.","index":229,"end_time":1088.34,"speaker_id":0,"start_time":1087.94,"speaker_name":null},{"text":"But I think it''s, you know, it''s something we want to explore because what we''re considering is like a couple different paths of the way that we''re thinking of replacing Sam''s spot.","index":230,"end_time":1103.14,"speaker_id":2,"start_time":1089.46,"speaker_name":null},{"text":"Is it going to be more of a, like, similar role to what Sam was doing, or are we going to hire more of like a CMO creative person to be marketing and then only If New north can handle the operational day to day marketing stuff that we still need to keep the lights on and Dan needs a two pager.","index":231,"end_time":1129.54,"speaker_id":2,"start_time":1103.54,"speaker_name":null},{"text":"Can we say we send it to you and get it turned around quickly?","index":232,"end_time":1133.62,"speaker_id":2,"start_time":1130.5,"speaker_name":null},{"text":"Like, like that''s the kind of, that we would pile on Sam''s plate all the time.","index":233,"end_time":1137.7,"speaker_id":2,"start_time":1133.62,"speaker_name":null},{"text":"Right.","index":234,"end_time":1138.5,"speaker_id":0,"start_time":1138.1,"speaker_name":null},{"text":"And quite honestly was like pretty unfair to when Sam''s trying to do other stuff and it''s like, okay, here''s, this is my new fire that I need you to help me put out.","index":235,"end_time":1148.11,"speaker_id":2,"start_time":1138.5,"speaker_name":null},{"text":"How realistic is it that you guys can take on that kind of stuff?","index":236,"end_time":1151.95,"speaker_id":2,"start_time":1148.83,"speaker_name":null},{"text":"I mean that''s the type of relationship we have with several clients.","index":237,"end_time":1154.91,"speaker_id":0,"start_time":1152.19,"speaker_name":null},{"text":"I mean we handle marketing operations for honestly a significant portion of our clients.","index":238,"end_time":1160.59,"speaker_id":0,"start_time":1155.55,"speaker_name":null},{"text":"Everything inside of HubSpot, sales, like any of their CRMs, website management, maintenance, new copy designs and documents, all that sort of stuff.","index":239,"end_time":1170.61,"speaker_id":0,"start_time":1162.03,"speaker_name":null},{"text":"Yeah, I think, yeah, I think New north would be well equipped to handle all this stuff.","index":240,"end_time":1175.73,"speaker_id":3,"start_time":1171.17,"speaker_name":null},{"text":"Like, you know, and Colin, I''m sure you''re kind of aware of how this worked.","index":241,"end_time":1181.13,"speaker_id":3,"start_time":1175.73,"speaker_name":null},{"text":"There''s, there''s not necessarily, you know, I can put together a list but it''s, it''s more like reactionary of like we talk about this effort and then okay, I got to make sure that HubSpot''s all set up to do that appropriately.","index":242,"end_time":1196.63,"speaker_id":3,"start_time":1181.13,"speaker_name":null},{"text":"And that''s, you know, landing page creation or editing, that''s any automation that needs to go in the back end so that we''re creating tasks, we''re notifying people, changing up properties, you know, responding to issues when things aren''t working correctly and then just, you know, you know, email creation.","index":243,"end_time":1218.43,"speaker_id":3,"start_time":1196.63,"speaker_name":null},{"text":"If we want to do an email campaign, coordinating with you know, what we''re talking about, like there''s some like daily stuff that like I''m kind of handling internally from marketing that again I think New north would be equipped to do which is, you know, hey, we want to run a campaign for the benchmark report.","index":244,"end_time":1235.54,"speaker_id":3,"start_time":1218.59,"speaker_name":null},{"text":"Let''s set up the social posts, let''s set up the emails.","index":245,"end_time":1238.1,"speaker_id":3,"start_time":1235.54,"speaker_name":null},{"text":"And then there''s more like Josh, you know, we''ll have like one of our Wednesday calls and it''s like, hey, you know, it would be great if we could get together a, just as an example like a closed lost campaign at this time and that''s, you know, putting together the sequence, like putting together the list, making sure that, you know, the list is curated and tailored and doesn''t have, you know, current prospects and whatever it is.","index":246,"end_time":1267.63,"speaker_id":3,"start_time":1238.1,"speaker_name":null},{"text":"Like just kind of all the back end marketing ops stuff that we do for all, for all the Initiatives that we.","index":247,"end_time":1273.67,"speaker_id":3,"start_time":1267.63,"speaker_name":null},{"text":"That we work on.","index":248,"end_time":1274.55,"speaker_id":3,"start_time":1273.67,"speaker_name":null},{"text":"Yeah, yeah.","index":249,"end_time":1276.64,"speaker_id":0,"start_time":1275.2,"speaker_name":null},{"text":"And Josh, really, any of the paths that you were outlining also?","index":250,"end_time":1279.76,"speaker_id":0,"start_time":1276.64,"speaker_name":null},{"text":"We.","index":251,"end_time":1280.04,"speaker_id":0,"start_time":1279.76,"speaker_name":null},{"text":"We have experience working with clients that way, too.","index":252,"end_time":1282.4,"speaker_id":0,"start_time":1280.04,"speaker_name":null},{"text":"So, for example, I have a few clients that do have, like a CMO or head of marketing role and they kind of own strategy.","index":253,"end_time":1288.92,"speaker_id":0,"start_time":1282.4,"speaker_name":null},{"text":"And then we are like, execution across the board.","index":254,"end_time":1291.84,"speaker_id":0,"start_time":1288.92,"speaker_name":null},{"text":"Like, they''re just like the visionary, and we execute across everything.","index":255,"end_time":1295.12,"speaker_id":0,"start_time":1291.84,"speaker_name":null},{"text":"Obviously, we have clients where we own the strategy and all of the execution as well.","index":256,"end_time":1300.16,"speaker_id":0,"start_time":1296.16,"speaker_name":null},{"text":"So we can fit really anywhere in that Venn diagram.","index":257,"end_time":1303.98,"speaker_id":0,"start_time":1300.64,"speaker_name":null},{"text":"Okay.","index":258,"end_time":1304.62,"speaker_id":2,"start_time":1304.14,"speaker_name":null},{"text":"Because I think the direction that we''re probably going to go is we''re going to get somebody that is, you know, like a marketing manager or director that''s going to do a lot of the operational marketing stuff that we''re doing, a lot of the stuff that we put on Sam''s plate.","index":259,"end_time":1318.22,"speaker_id":2,"start_time":1304.62,"speaker_name":null},{"text":"We got to get them up and running.","index":260,"end_time":1319.5,"speaker_id":2,"start_time":1318.22,"speaker_name":null},{"text":"But then we''re also going to hire, like, a fractional cmo.","index":261,"end_time":1322.7,"speaker_id":2,"start_time":1319.5,"speaker_name":null},{"text":"And that was kind of the plan when Sam was staying too, was like, we''re going to get somebody to come in and work whatever, 10 to 20 hours a week with us that''s doing more of, like, you know, visionary work and has, you know, experience, like, with SaaS companies going from 3 million in ARR to 10 million in ARR.","index":262,"end_time":1345.839,"speaker_id":2,"start_time":1323.74,"speaker_name":null},{"text":"And that''s like, that''s what their job has always been.","index":263,"end_time":1347.84,"speaker_id":2,"start_time":1345.92,"speaker_name":null},{"text":"But they''re not getting their hands dirty and they''re not doing any of, like, the hard work.","index":264,"end_time":1352.08,"speaker_id":2,"start_time":1347.92,"speaker_name":null},{"text":"They''re just, like, doing the strategy.","index":265,"end_time":1354.48,"speaker_id":2,"start_time":1352.08,"speaker_name":null},{"text":"Um, so I think that''s probably the route that we''re going to go, but we just, you know, this.","index":266,"end_time":1360.57,"speaker_id":2,"start_time":1355.21,"speaker_name":null},{"text":"Again, this.","index":267,"end_time":1361.45,"speaker_id":2,"start_time":1360.65,"speaker_name":null},{"text":"I''m happy for Sam.","index":268,"end_time":1362.97,"speaker_id":2,"start_time":1361.85,"speaker_name":null},{"text":"This is a great opportunity for him.","index":269,"end_time":1364.57,"speaker_id":2,"start_time":1362.97,"speaker_name":null},{"text":"This was, like, new news for Rob and I.","index":270,"end_time":1366.97,"speaker_id":2,"start_time":1364.81,"speaker_name":null},{"text":"So now we''re like, just trying to figure out what, you know.","index":271,"end_time":1369.81,"speaker_id":2,"start_time":1366.97,"speaker_name":null},{"text":"Yeah.","index":272,"end_time":1370.13,"speaker_id":0,"start_time":1369.81,"speaker_name":null},{"text":"What cards you have.","index":273,"end_time":1370.81,"speaker_id":0,"start_time":1370.13,"speaker_name":null},{"text":"Yeah, I got you.","index":274,"end_time":1371.77,"speaker_id":0,"start_time":1370.81,"speaker_name":null},{"text":"Yeah.","index":275,"end_time":1372.29,"speaker_id":0,"start_time":1371.93,"speaker_name":null},{"text":"And another client that Nina and I work with had a fractional CMO come in for six months.","index":276,"end_time":1377.05,"speaker_id":0,"start_time":1372.29,"speaker_name":null},{"text":"We worked very hand in hand with her.","index":277,"end_time":1378.69,"speaker_id":0,"start_time":1377.05,"speaker_name":null},{"text":"And during that, towards the latter half, they hired a new head of marketing.","index":278,"end_time":1382.29,"speaker_id":0,"start_time":1378.69,"speaker_name":null},{"text":"And now we work very closely with them.","index":279,"end_time":1383.93,"speaker_id":0,"start_time":1382.29,"speaker_name":null},{"text":"Um, so, yeah, we work in all sorts of flavors.","index":280,"end_time":1387.65,"speaker_id":0,"start_time":1384.61,"speaker_name":null},{"text":"Yeah.","index":281,"end_time":1389.09,"speaker_id":3,"start_time":1388.61,"speaker_name":null},{"text":"Josh, on your fractional CMO issue as well.","index":282,"end_time":1392.85,"speaker_id":3,"start_time":1390.37,"speaker_name":null},{"text":"My dad does fractional CMO work right now as, like, his, like, semi retirement plan.","index":283,"end_time":1402.09,"speaker_id":3,"start_time":1394.21,"speaker_name":null},{"text":"Like, he has a couple clients is.","index":284,"end_time":1403.89,"speaker_id":3,"start_time":1402.09,"speaker_name":null},{"text":"That''s what he does.","index":285,"end_time":1406.05,"speaker_id":3,"start_time":1405.25,"speaker_name":null},{"text":"And I was talking to him about what you had told me, and he.","index":286,"end_time":1411.01,"speaker_id":3,"start_time":1406.13,"speaker_name":null},{"text":"He offered to, you know, not necessarily be your hire of a fractional cmo, but if you''re looking just for some guidance on how to hire a fractional CMO or what you should be looking for, things like that.","index":287,"end_time":1423.54,"speaker_id":3,"start_time":1411.01,"speaker_name":null},{"text":"He offered to speak with you and Rob as well too, if you want to take them up on that.","index":288,"end_time":1427.78,"speaker_id":3,"start_time":1423.7,"speaker_name":null},{"text":"Well, I mean, I think we''re taking whatever help we can get, so.","index":289,"end_time":1431.62,"speaker_id":2,"start_time":1428.02,"speaker_name":null},{"text":"Yeah, I''ll connect you.","index":290,"end_time":1432.9,"speaker_id":3,"start_time":1431.62,"speaker_name":null},{"text":"I know Rob''s, you know, Rob''s big thing is whatever role we hire for his very strong preferences out there in Seattle, Bellevue area, so that, you know, they''re not remote from.","index":291,"end_time":1450.34,"speaker_id":2,"start_time":1432.9,"speaker_name":null},{"text":"So like it was.","index":292,"end_time":1451.3,"speaker_id":2,"start_time":1450.34,"speaker_name":null},{"text":"I''m sure it was hard for you at the beginning, but you''ve been with, with us for so long that it''s like you have so much institutional knowledge.","index":293,"end_time":1459.86,"speaker_id":2,"start_time":1452.5,"speaker_name":null},{"text":"Yes, it will be easier to get somebody ramped up quicker if they''re like living and breathing in the office all the time.","index":294,"end_time":1465.94,"speaker_id":2,"start_time":1460.82,"speaker_name":null},{"text":"But that obviously narrows the pull down.","index":295,"end_time":1467.86,"speaker_id":2,"start_time":1465.94,"speaker_name":null},{"text":"Yeah, it narrows the bulldown.","index":296,"end_time":1469.73,"speaker_id":3,"start_time":1468.41,"speaker_name":null},{"text":"I think if you''re gonna hire fractional cmo, I would definitely hire someone in your area so that they can come to the office.","index":297,"end_time":1475.61,"speaker_id":3,"start_time":1469.73,"speaker_name":null},{"text":"I think that''ll be very beneficial.","index":298,"end_time":1477.89,"speaker_id":3,"start_time":1475.61,"speaker_name":null},{"text":"But I think my dad might be able to give you guys some insight into a little bit more how it works and like, what you should be looking for in candidates and like, the kind of services they''re gonna provide for you.","index":299,"end_time":1491.49,"speaker_id":3,"start_time":1477.89,"speaker_name":null},{"text":"Because he''s been doing this for, I think, two or three years now.","index":300,"end_time":1494.61,"speaker_id":3,"start_time":1491.49,"speaker_name":null},{"text":"And it''s been pretty, it''s been pretty good for him.","index":301,"end_time":1498.91,"speaker_id":3,"start_time":1494.61,"speaker_name":null},{"text":"But like, he, he''s had experiences where like other.","index":302,"end_time":1502.59,"speaker_id":3,"start_time":1498.91,"speaker_name":null},{"text":"Some of his clients have been burned by fractional CMOs before, like, where it didn''t work out for a variety of different factors or whatnot.","index":303,"end_time":1510.95,"speaker_id":3,"start_time":1502.75,"speaker_name":null},{"text":"So I''ll connect you guys.","index":304,"end_time":1512.43,"speaker_id":3,"start_time":1510.95,"speaker_name":null},{"text":"Big Mike.","index":305,"end_time":1513.79,"speaker_id":2,"start_time":1513.07,"speaker_name":null},{"text":"Big Mike.","index":306,"end_time":1515.15,"speaker_id":3,"start_time":1514.43,"speaker_name":null},{"text":"Let''s go.","index":307,"end_time":1515.95,"speaker_id":2,"start_time":1515.39,"speaker_name":null},{"text":"Semi.","index":308,"end_time":1516.31,"speaker_id":3,"start_time":1515.95,"speaker_name":null},{"text":"His, his semi retirement plan.","index":309,"end_time":1518.19,"speaker_id":3,"start_time":1516.31,"speaker_name":null},{"text":"Just can''t quit.","index":310,"end_time":1519.07,"speaker_id":2,"start_time":1518.27,"speaker_name":null},{"text":"Just can''t get, get him out.","index":311,"end_time":1520.39,"speaker_id":2,"start_time":1519.07,"speaker_name":null},{"text":"Can''t quit.","index":312,"end_time":1520.87,"speaker_id":3,"start_time":1520.39,"speaker_name":null},{"text":"He''s not a good, he''s not a good sit or sit around all day type of guy.","index":313,"end_time":1526.6,"speaker_id":3,"start_time":1520.87,"speaker_name":null},{"text":"So that''s what I thought my dad was going to be.","index":314,"end_time":1529.12,"speaker_id":2,"start_time":1526.68,"speaker_name":null},{"text":"And then my dad retired and he just was like, I''m, I''m good.","index":315,"end_time":1533.4,"speaker_id":2,"start_time":1529.12,"speaker_name":null},{"text":"Play a lot of golf.","index":316,"end_time":1534.6,"speaker_id":2,"start_time":1533.64,"speaker_name":null},{"text":"And I like, all of a sudden he''s like using iPads and iPhones where he didn''t do that ever.","index":317,"end_time":1542.2,"speaker_id":2,"start_time":1534.6,"speaker_name":null},{"text":"He''s like drinking coffee.","index":318,"end_time":1543.48,"speaker_id":2,"start_time":1542.2,"speaker_name":null},{"text":"I''m like, you worked for 40 something years, you never drank a cup of coffee.","index":319,"end_time":1547.36,"speaker_id":2,"start_time":1543.48,"speaker_name":null},{"text":"Now that he''s retired, he''s like this coffee connoisseur.","index":320,"end_time":1550.2,"speaker_id":2,"start_time":1547.36,"speaker_name":null},{"text":"That''s funny.","index":321,"end_time":1552.2,"speaker_id":3,"start_time":1551.56,"speaker_name":null},{"text":"My dad plays a lot of pickleball, I will say that.","index":322,"end_time":1554.56,"speaker_id":3,"start_time":1552.28,"speaker_name":null},{"text":"But he Gets it out, and he gets it out in the morning, and then, like, works the rest of the day, basically.","index":323,"end_time":1559.56,"speaker_id":3,"start_time":1554.56,"speaker_name":null},{"text":"Yeah.","index":324,"end_time":1560.72,"speaker_id":3,"start_time":1560.36,"speaker_name":null},{"text":"It''s a nice life.","index":325,"end_time":1561.56,"speaker_id":3,"start_time":1560.72,"speaker_name":null},{"text":"Someday.","index":326,"end_time":1563.32,"speaker_id":2,"start_time":1562.68,"speaker_name":null},{"text":"Okay, Colin, so I don''t know, what.","index":327,"end_time":1566.84,"speaker_id":2,"start_time":1564.44,"speaker_name":null},{"text":"Do you want me to have Rob join our Monday call, or do you want to schedule a separate call?","index":328,"end_time":1571.88,"speaker_id":2,"start_time":1566.84,"speaker_name":null},{"text":"I mean, you know, we got to figure out also, like, once we.","index":329,"end_time":1575.32,"speaker_id":2,"start_time":1571.88,"speaker_name":null},{"text":"Once, I guess, or you tell me, what would you need to put together, like, a.","index":330,"end_time":1581.29,"speaker_id":2,"start_time":1575.32,"speaker_name":null},{"text":"This is what it would look like if we were going to bring you on kind of a. Yeah, I just.","index":331,"end_time":1586.33,"speaker_id":2,"start_time":1581.29,"speaker_name":null},{"text":"I mean, I kind of have the list of things that Sam went through on this call, and I can just put all of that into a document.","index":332,"end_time":1591.77,"speaker_id":0,"start_time":1586.65,"speaker_name":null},{"text":"But the thing that.","index":333,"end_time":1593.37,"speaker_id":0,"start_time":1591.77,"speaker_name":null},{"text":"I don''t even know if concern is the right word, but the thing that''s just in my mind is, like, anything that Sam, you just handle and, like, don''t even think about that.","index":334,"end_time":1601.86,"speaker_id":0,"start_time":1593.77,"speaker_name":null},{"text":"I want to make sure that we have mapped and, like, we understand exactly what the expectation is.","index":335,"end_time":1607.06,"speaker_id":0,"start_time":1601.86,"speaker_name":null},{"text":"So I think we should use Monday''s time for that.","index":336,"end_time":1610.66,"speaker_id":0,"start_time":1608.5,"speaker_name":null},{"text":"If you can give me Rob''s email, I''ll add them to our invite.","index":337,"end_time":1613.46,"speaker_id":0,"start_time":1610.82,"speaker_name":null},{"text":"And honestly, Sam, if you''re willing, I know you''re out in, like, a week or so, but you have those hours that you''re talking about any conversation, like, hey, you know, this was the request.","index":338,"end_time":1624.62,"speaker_id":0,"start_time":1614.34,"speaker_name":null},{"text":"This is how we''re thinking about handling it and just confirming that you didn''t have any other type of process, things like that.","index":339,"end_time":1630.08,"speaker_id":0,"start_time":1624.62,"speaker_name":null},{"text":"Yeah, I want to make the change.","index":340,"end_time":1631.88,"speaker_id":3,"start_time":1630.56,"speaker_name":null},{"text":"As seamless as possible for.","index":341,"end_time":1633.44,"speaker_id":0,"start_time":1631.88,"speaker_name":null},{"text":"For you guys.","index":342,"end_time":1634.16,"speaker_id":0,"start_time":1633.44,"speaker_name":null},{"text":"Yeah.","index":343,"end_time":1635.12,"speaker_id":3,"start_time":1634.56,"speaker_name":null},{"text":"So, like I said, like, I. I will be available for, you know, a couple hours on the side to help ease the transition.","index":344,"end_time":1642.72,"speaker_id":3,"start_time":1635.2,"speaker_name":null},{"text":"So, like, you know, my new role is three days a week in the office, so I''ll be home Mondays and Fridays, so I''ll have a little bit more availability if we need to jump on, like, a call or a huddle for things.","index":345,"end_time":1655.92,"speaker_id":3,"start_time":1642.88,"speaker_name":null},{"text":"But, you know, you can always slack me and, like, I. I can get back to you later.","index":346,"end_time":1663.14,"speaker_id":3,"start_time":1657.5,"speaker_name":null},{"text":"Like, you can always send me things that I can work on at night and stuff.","index":347,"end_time":1667.38,"speaker_id":3,"start_time":1663.14,"speaker_name":null},{"text":"And, like, if things pop up that, you know, I typically handle, that someone from PTO Exchange hits me with, like, I can kind of mark that down and show you the process or, like, transition it over to you in this interim period as well.","index":348,"end_time":1682.54,"speaker_id":3,"start_time":1667.38,"speaker_name":null},{"text":"So.","index":349,"end_time":1682.9,"speaker_id":3,"start_time":1682.54,"speaker_name":null},{"text":"Yeah.","index":350,"end_time":1683.34,"speaker_id":0,"start_time":1682.9,"speaker_name":null},{"text":"Yeah, I appreciate that.","index":351,"end_time":1684.28,"speaker_id":0,"start_time":1683.52,"speaker_name":null},{"text":"And I think you''ve seen, like, we''re capable, you know, more than capable in HubSpot, So I would really like to treat it as, like, we get a request, and I''m like, here''s exactly how we would do this from our like industry standard practices.","index":352,"end_time":1698.16,"speaker_id":0,"start_time":1684.28,"speaker_name":null},{"text":"But it''s more the nuances that, that have become accustomed through PTO exchange.","index":353,"end_time":1703.6,"speaker_id":0,"start_time":1698.32,"speaker_name":null},{"text":"Yeah, I mean most of the basic marketing stuff, like I''m sure you guys will understand how to do and you know, doesn''t require a ton of like training or like teaching you what to do.","index":354,"end_time":1716.92,"speaker_id":3,"start_time":1703.76,"speaker_name":null},{"text":"I think more so it''s like, you know, well, I''ll get requests for like we need to update properties with new dropdown options or we do some design work that like is on an ad hoc basis.","index":355,"end_time":1731.12,"speaker_id":3,"start_time":1717.16,"speaker_name":null},{"text":"Like we need a one pager or you know, we do these client communication flyers that are all templated out in Figma, which I can also share with you guys.","index":356,"end_time":1740.1,"speaker_id":3,"start_time":1731.12,"speaker_name":null},{"text":"So you''ll like have the FIGMA files that I use.","index":357,"end_time":1743.34,"speaker_id":3,"start_time":1740.1,"speaker_name":null},{"text":"They''re a bit messy, I will say that.","index":358,"end_time":1746.26,"speaker_id":3,"start_time":1744.06,"speaker_name":null},{"text":"But you know, there, it''s all in there and like it''s kind of just, you know.","index":359,"end_time":1753.98,"speaker_id":3,"start_time":1746.26,"speaker_name":null},{"text":"Yeah.","index":360,"end_time":1754.34,"speaker_id":3,"start_time":1753.98,"speaker_name":null},{"text":"Like going through the motions and updating what, whatever needs to be done.","index":361,"end_time":1758.66,"speaker_id":3,"start_time":1754.34,"speaker_name":null},{"text":"And then like I said, the hey, we want to do a campaign.","index":362,"end_time":1761.62,"speaker_id":3,"start_time":1758.66,"speaker_name":null},{"text":"Hey, we want to make a list.","index":363,"end_time":1762.62,"speaker_id":3,"start_time":1761.62,"speaker_name":null},{"text":"Hey, we want to make a landing page.","index":364,"end_time":1763.9,"speaker_id":3,"start_time":1762.62,"speaker_name":null},{"text":"Like, you know, you guys are all equipped to handle any of those requests.","index":365,"end_time":1768.06,"speaker_id":3,"start_time":1763.9,"speaker_name":null},{"text":"Yeah, everything you listed, you know, fully comfortable and, and confident in handling that stuff.","index":366,"end_time":1772.98,"speaker_id":0,"start_time":1768.06,"speaker_name":null},{"text":"So yeah, I just want to make sure that it''s as seamless as possible for Josh and the team.","index":367,"end_time":1778.02,"speaker_id":0,"start_time":1773.54,"speaker_name":null},{"text":"Yeah, there''s.","index":368,"end_time":1779.42,"speaker_id":3,"start_time":1778.58,"speaker_name":null},{"text":"And you guys are better at technology than even I am.","index":369,"end_time":1782.3,"speaker_id":3,"start_time":1779.42,"speaker_name":null},{"text":"But like there''ll be technology requests as to like, so.","index":370,"end_time":1787.1,"speaker_id":3,"start_time":1782.3,"speaker_name":null},{"text":"Hey, my HubSpot isn''t letting me export something or my set up calendly.","index":371,"end_time":1794.28,"speaker_id":3,"start_time":1787.1,"speaker_name":null},{"text":"Right?","index":372,"end_time":1794.6,"speaker_id":0,"start_time":1794.28,"speaker_name":null},{"text":"Yeah, yeah, whatever.","index":373,"end_time":1795.6,"speaker_id":3,"start_time":1794.6,"speaker_name":null},{"text":"Calendly isn''t, you know, put it going on my calendar or whatever.","index":374,"end_time":1802.04,"speaker_id":3,"start_time":1795.6,"speaker_name":null},{"text":"We use a tool called sales, which I can''t find my sales reach asset or whatever, whatever it may be.","index":375,"end_time":1808,"speaker_id":3,"start_time":1802.04,"speaker_name":null},{"text":"It''s like stuff like that.","index":376,"end_time":1809.36,"speaker_id":3,"start_time":1808.16,"speaker_name":null},{"text":"Cool.","index":377,"end_time":1810,"speaker_id":0,"start_time":1809.52,"speaker_name":null},{"text":"All right.","index":378,"end_time":1810.6,"speaker_id":0,"start_time":1810.24,"speaker_name":null},{"text":"Yeah, that sounds good.","index":379,"end_time":1811.52,"speaker_id":0,"start_time":1810.6,"speaker_name":null},{"text":"And it looks like Rob is available on Monday for our time, so his email is just robtoexchange.com so you can send them the invite for that one.","index":380,"end_time":1820.37,"speaker_id":2,"start_time":1812.72,"speaker_name":null},{"text":"Perfect.","index":381,"end_time":1821.09,"speaker_id":0,"start_time":1820.53,"speaker_name":null},{"text":"And I know you guys are in your search, but if you need me to share any fractional CMOs that I''ve worked with in the past or anything like that, let me know as well.","index":382,"end_time":1834.21,"speaker_id":0,"start_time":1826.13,"speaker_name":null},{"text":"If you have any that are in the Seattle area.","index":383,"end_time":1837.09,"speaker_id":2,"start_time":1835.01,"speaker_name":null},{"text":"You Rolodex, I''d have to check.","index":384,"end_time":1841.01,"speaker_id":2,"start_time":1838.29,"speaker_name":null},{"text":"Okay.","index":385,"end_time":1841.73,"speaker_id":2,"start_time":1841.17,"speaker_name":null},{"text":"I think they''ve mostly been on the east coast.","index":386,"end_time":1843.81,"speaker_id":0,"start_time":1841.89,"speaker_name":null},{"text":"Okay.","index":387,"end_time":1844.7,"speaker_id":2,"start_time":1844.22,"speaker_name":null},{"text":"Okay, cool.","index":388,"end_time":1846.98,"speaker_id":0,"start_time":1846.14,"speaker_name":null},{"text":"All right, well, looking forward to the conversation Monday then.","index":389,"end_time":1849.62,"speaker_id":0,"start_time":1846.98,"speaker_name":null},{"text":"Sam again, best of luck, excited for you and miss working with you very closely.","index":390,"end_time":1855.58,"speaker_id":0,"start_time":1849.62,"speaker_name":null},{"text":"Yes.","index":391,"end_time":1856.46,"speaker_id":3,"start_time":1856.06,"speaker_name":null},{"text":"Colin, thank you so much.","index":392,"end_time":1857.66,"speaker_id":3,"start_time":1856.46,"speaker_name":null},{"text":"I appreciate the well wishes and again you and your team have been a pleasure to work with.","index":393,"end_time":1863.26,"speaker_id":3,"start_time":1857.66,"speaker_name":null},{"text":"Have really been a big help to PTO exchange.","index":394,"end_time":1865.42,"speaker_id":3,"start_time":1863.34,"speaker_name":null},{"text":"So thank you for that.","index":395,"end_time":1866.3,"speaker_id":3,"start_time":1865.42,"speaker_name":null},{"text":"Yeah, appreciate it.","index":396,"end_time":1867.38,"speaker_id":0,"start_time":1866.38,"speaker_name":null},{"text":"And if we, well, we''ll talk on Monday so I''ll wish you a happy early birthday then.","index":397,"end_time":1871.9,"speaker_id":0,"start_time":1867.38,"speaker_name":null},{"text":"Thank you.","index":398,"end_time":1873.88,"speaker_id":3,"start_time":1873.48,"speaker_name":null},{"text":"Appreciate it.","index":399,"end_time":1874.68,"speaker_id":3,"start_time":1873.88,"speaker_name":null},{"text":"Awesome.","index":400,"end_time":1875.32,"speaker_id":0,"start_time":1874.68,"speaker_name":null},{"text":"Anything else that you guys wanted to chat through in this last minute and a half?","index":401,"end_time":1878.6,"speaker_id":0,"start_time":1875.48,"speaker_name":null},{"text":"No, that''s everything.","index":402,"end_time":1879.88,"speaker_id":2,"start_time":1878.76,"speaker_name":null},{"text":"I think that''s good luck this weekend to your commanders.","index":403,"end_time":1883.32,"speaker_id":2,"start_time":1880.04,"speaker_name":null},{"text":"Oh yeah.","index":404,"end_time":1884.08,"speaker_id":3,"start_time":1883.56,"speaker_name":null},{"text":"Commander''s Eagles this weekend.","index":405,"end_time":1885.36,"speaker_id":3,"start_time":1884.08,"speaker_name":null},{"text":"Con.","index":406,"end_time":1885.6,"speaker_id":3,"start_time":1885.36,"speaker_name":null},{"text":"You''re not excited?","index":407,"end_time":1886.32,"speaker_id":3,"start_time":1885.6,"speaker_name":null},{"text":"Come on, big matchup.","index":408,"end_time":1887.88,"speaker_id":3,"start_time":1886.32,"speaker_name":null},{"text":"Jaden''s done for the season.","index":409,"end_time":1889.2,"speaker_id":0,"start_time":1888.039,"speaker_name":null},{"text":"It''s just watching Marcus Mariota go out there and try and hurdle someone.","index":410,"end_time":1892.28,"speaker_id":0,"start_time":1889.2,"speaker_name":null},{"text":"It''s also at like Saturday at 5pm which is like a weird.","index":411,"end_time":1896.96,"speaker_id":3,"start_time":1892.28,"speaker_name":null},{"text":"I think we have a Christmas game.","index":412,"end_time":1898,"speaker_id":0,"start_time":1896.96,"speaker_name":null},{"text":"I think that''s why, I guess, I.","index":413,"end_time":1900.25,"speaker_id":0,"start_time":1898,"speaker_name":null},{"text":"Mean I have a like Hanukkah party in the middle of it, which I''m like, okay, like it''ll be on the tv.","index":414,"end_time":1906.33,"speaker_id":3,"start_time":1900.25,"speaker_name":null},{"text":"But like gave me an experience to leave.","index":415,"end_time":1908.89,"speaker_id":3,"start_time":1906.33,"speaker_name":null},{"text":"I''m leaving earlier in the day than I normally would because I''m going to the Oregon JMU game.","index":416,"end_time":1913.17,"speaker_id":2,"start_time":1908.89,"speaker_name":null},{"text":"Oh yeah.","index":417,"end_time":1914.37,"speaker_id":3,"start_time":1913.73,"speaker_name":null},{"text":"So my neighbor who is a duck and I are going down and he was like, do you want to leave early so we can get somewhere so you can sit and watch the Eagles commanders game?","index":418,"end_time":1923.37,"speaker_id":2,"start_time":1915.17,"speaker_name":null},{"text":"I was like, sure, why not?","index":419,"end_time":1924.21,"speaker_id":2,"start_time":1923.37,"speaker_name":null},{"text":"Let''s get down there, find a bar outside the stadium and go watch the game.","index":420,"end_time":1927.74,"speaker_id":2,"start_time":1924.21,"speaker_name":null},{"text":"So there you go.","index":421,"end_time":1928.46,"speaker_id":0,"start_time":1927.74,"speaker_name":null},{"text":"You got your purple Dukes jersey.","index":422,"end_time":1929.94,"speaker_id":0,"start_time":1928.46,"speaker_name":null},{"text":"I got my, I got my JMU gear ready to go.","index":423,"end_time":1932.42,"speaker_id":2,"start_time":1930.1,"speaker_name":null},{"text":"Duke''s jersey.","index":424,"end_time":1933.86,"speaker_id":2,"start_time":1933.06,"speaker_name":null},{"text":"But I got, I got some JMU gear that I''ll be wearing.","index":425,"end_time":1935.86,"speaker_id":2,"start_time":1933.86,"speaker_name":null},{"text":"Where''s the, where''s the game, Josh?","index":426,"end_time":1938.66,"speaker_id":3,"start_time":1936.5,"speaker_name":null},{"text":"Yeah, at Oregon.","index":427,"end_time":1940.02,"speaker_id":2,"start_time":1938.9,"speaker_name":null},{"text":"The first round games are at the lower, you know, the better teams.","index":428,"end_time":1943.54,"speaker_id":2,"start_time":1940.18,"speaker_name":null},{"text":"Home stadium, better teams.","index":429,"end_time":1944.82,"speaker_id":3,"start_time":1943.54,"speaker_name":null},{"text":"Is that far away from you or.","index":430,"end_time":1946.34,"speaker_id":3,"start_time":1944.82,"speaker_name":null},{"text":"It''S like a five hour drive.","index":431,"end_time":1947.78,"speaker_id":2,"start_time":1946.34,"speaker_name":null},{"text":"Oh man.","index":432,"end_time":1949.06,"speaker_id":3,"start_time":1948.34,"speaker_name":null},{"text":"Pretty.","index":433,"end_time":1949.62,"speaker_id":3,"start_time":1949.22,"speaker_name":null},{"text":"Pretty decent drive.","index":434,"end_time":1950.66,"speaker_id":3,"start_time":1949.62,"speaker_name":null},{"text":"Yeah, we''re going down, we''re going to stay the night, wake up first thing in the morning, head back.","index":435,"end_time":1954.48,"speaker_id":2,"start_time":1951.08,"speaker_name":null},{"text":"Probably a scenic drive though.","index":436,"end_time":1955.76,"speaker_id":0,"start_time":1954.48,"speaker_name":null},{"text":"I imagine a lot of it''s pretty nice.","index":437,"end_time":1958.28,"speaker_id":2,"start_time":1955.76,"speaker_name":null},{"text":"Yeah.","index":438,"end_time":1958.84,"speaker_id":0,"start_time":1958.28,"speaker_name":null},{"text":"Yeah, you got lucky with that.","index":439,"end_time":1960.92,"speaker_id":3,"start_time":1959,"speaker_name":null},{"text":"You got lucky with them getting Oregon, right?","index":440,"end_time":1963.48,"speaker_id":3,"start_time":1960.92,"speaker_name":null},{"text":"Well, once we like, as we saw what was going on, you knew Oregon was going to be the 5 seed and we''re like obviously if JMU makes it, we''re going to be the.","index":441,"end_time":1971.12,"speaker_id":2,"start_time":1963.56,"speaker_name":null},{"text":"Whatever the lowest seed is that we can make.","index":442,"end_time":1972.76,"speaker_id":2,"start_time":1971.12,"speaker_name":null},{"text":"So as the games were playing out, me and my neighbor were like, this could be the only time ever that JMU plays Oregon.","index":443,"end_time":1978.28,"speaker_id":2,"start_time":1972.76,"speaker_name":null},{"text":"So.","index":444,"end_time":1978.6,"speaker_id":2,"start_time":1978.28,"speaker_name":null},{"text":"Yeah, you''re lucked out.","index":445,"end_time":1980.48,"speaker_id":3,"start_time":1979.52,"speaker_name":null},{"text":"It could have been, you know, in.","index":446,"end_time":1981.8,"speaker_id":3,"start_time":1980.48,"speaker_name":null},{"text":"In Texas or something.","index":447,"end_time":1983.52,"speaker_id":3,"start_time":1981.8,"speaker_name":null},{"text":"Yeah, I could have been, like, all over the place.","index":448,"end_time":1985.36,"speaker_id":3,"start_time":1983.52,"speaker_name":null},{"text":"Yeah, that''s cool.","index":449,"end_time":1986.64,"speaker_id":3,"start_time":1985.36,"speaker_name":null},{"text":"That''s fun.","index":450,"end_time":1987.12,"speaker_id":3,"start_time":1986.64,"speaker_name":null},{"text":"I''ll get to see them get smashed live and in person.","index":451,"end_time":1989.68,"speaker_id":2,"start_time":1987.12,"speaker_name":null},{"text":"That''ll be great.","index":452,"end_time":1990.56,"speaker_id":2,"start_time":1989.68,"speaker_name":null},{"text":"You made the playoff.","index":453,"end_time":1992.16,"speaker_id":3,"start_time":1991.04,"speaker_name":null},{"text":"That''s a success for jmeo.","index":454,"end_time":1994.16,"speaker_id":3,"start_time":1992.32,"speaker_name":null},{"text":"Well, good luck on.","index":455,"end_time":1995.36,"speaker_id":2,"start_time":1994.64,"speaker_name":null},{"text":"We''ll talk all about.","index":456,"end_time":1996.2,"speaker_id":2,"start_time":1995.36,"speaker_name":null},{"text":"We''ll reserve some time on Monday''s call to talk about the Eagles commanders recap.","index":457,"end_time":2000.16,"speaker_id":2,"start_time":1996.2,"speaker_name":null},{"text":"Do you actually want me to come to the meeting or not?","index":458,"end_time":2003.68,"speaker_id":0,"start_time":2001.84,"speaker_name":null},{"text":"Now you guys are gonna win, but we''ll see.","index":459,"end_time":2009.1,"speaker_id":2,"start_time":2006.58,"speaker_name":null},{"text":"I don''t know.","index":460,"end_time":2009.78,"speaker_id":0,"start_time":2009.1,"speaker_name":null},{"text":"Yeah, I don''t know.","index":461,"end_time":2011.62,"speaker_id":0,"start_time":2010.26,"speaker_name":null},{"text":"All right, I''ll see you guys.","index":462,"end_time":2013.94,"speaker_id":0,"start_time":2012.9,"speaker_name":null},{"text":"Yeah.","index":463,"end_time":2014.42,"speaker_id":3,"start_time":2013.94,"speaker_name":null},{"text":"Go Bird.","index":464,"end_time":2014.98,"speaker_id":2,"start_time":2014.42,"speaker_name":null},{"text":"Have a good weekend, everyone.","index":465,"end_time":2015.94,"speaker_id":3,"start_time":2014.98,"speaker_name":null}],"dateString":"2025-12-18T18:30:00.000Z","host_email":"colin.costigan@marketersindemand.com","meeting_link":"https://us02web.zoom.us/j/87477024015?pwd=gVpnKPDuNsoZ0giaFoA7gicVcI6afV.1","participants":["colin.costigan@marketersindemand.com,sam@ptoexchange.com,nina.belina@marketersindemand.com,josh@ptoexchange.com","sam@ptoexchange.com","nina.belina@marketersindemand.com","josh@ptoexchange.com"],"transcript_url":"https://app.fireflies.ai/view/01KC7M021KMYX346XTS0YZT4MM","organizer_email":"colin.costigan@marketersindemand.com"}'::jsonb,
  '{"label":"positive","confidence":0.9,"bullets":["Confirmed demo video delivery shifted to Tuesday; client aligned as launch is in January.","Shared that slide deck design is on track for Monday delivery; aligned on timeline.","Discussed conversion gap on Benchmark Report and agreed to test LinkedIn PDF lead gen.","Sam announced departure; team planning handoff of marketing ops to New North.","Aligned on transition plan; Monday meeting set to define HubSpot and support scope."],"highlights":[{"quote":"We have all of those documents ready for you guys to review.","speaker":"Unknown"},{"quote":"We''ll have that to you on Tuesday then.","speaker":"Unknown"},{"quote":"I will be available for them in the interim time as they look for a replacement.","speaker":"Unknown"}],"topics":["delivery","handoff","ops","ads","conversion"],"model":"openai/gpt-4","version":1,"generated_at":"2025-12-18T00:00:00Z"}'::jsonb,
